var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음질이 불안하군. 균열을 벗어날 때 음향 센서가 망가졌나.","JPN":"音質が不安定だな。亀裂を抜け出る時に音響センサーが壊れたのか。","ENG":"The sound quality is unstable. Did my sensor break while we were leaving the rift?","TWN":"音質不穩定呢。是脫離裂縫時音響感測器摔壞了嗎。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 뛰어들기 직전에 탐식자가 무슨 조치를 취했나 보군.","JPN":"だが、飛び込む前に貪食者が何かの措置をしたようだ。","ENG":"I assume the Devourer did something just before we jumped in.","TWN":"不過跳進來之前，貪食者似乎已經採取了什麼措施。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"불행 중 다행이야. 안 그랬으면 우리 모두 원자 단위로 분해되었을 걸세.","JPN":"不幸中の幸いだ。そうでなかったら私たち全員、原子の単位で分解されていたことだろう。","ENG":"Lucky it wasn't worse. We would have disintegrated at the molecular level otherwise.","TWN":"真是不幸中的大幸。不然的話，我們該被分解成原子單位了。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걷기 힘들다면 말하게. 지팡이로 쓸 만한 막대기를 구해 오지.","JPN":"歩きづらければ言ってくれたまえ。杖に使えそうな木の棒を探してこよう。","ENG":"Let us know if it's hard for you to walk. I'll go find you a stick or something you can put your weight on.","TWN":"不能走的話就說一聲。我給你找根棍子當拐杖。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……무슨 기회가 남았다는 거예요?","JPN":"……何のチャンスが残っているというのですか？","ENG":"What did you mean by that I still have a chance?","TWN":"……你說我還有什麼機會？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 그야 의식을 막을 기회 아닌가.","JPN":"む？　それは当然、儀式を止めるチャンスさ。","ENG":"Hmm? I meant a chance to stop the ritual.","TWN":"嗯？不就是阻止儀式的機會嗎。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어서 다른 일행을 찾아야 하네. 자네 혼자서 살아남기는 힘들어.","JPN":"急いで他の者たちを探さなくては。君一人で生き残るのは厳しいだろう。","ENG":"For now, we must find the others. Out here, it's near impossible for you to survive alone.","TWN":"必須快點找到其他人。你一個人很難活下去。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"찾아서, 어떡하려고요.","JPN":"探して、どうするのですか。","ENG":"Find them? And then what?","TWN":"找到後，要怎麼辦。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"봤을 거 아니에요. 힘으로는 에델을 못 이겨요.","JPN":"ご覧になったでしょう。力ではエデルには勝てませんわ。","ENG":"You saw what she can do. I cannot defeat Edel by force.","TWN":"你不是已經看到了嗎，靠力量贏不了艾瑟兒。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"또 실패할 바에는… 차라리 여기서 죽는 편이 나아요.","JPN":"また失敗するくらいなら……いっそここで死んだ方がマシです。","ENG":"I would rather die here... than fail again.","TWN":"比起再次失敗……我還不如乾脆死在這裡。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시간이 부족해. 어서 기운 차리게.","JPN":"時間がないんだ。早く元気を出したまえ。","ENG":"We don't have time. You must get up.","TWN":"沒時間了，你快點打起精神來。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상대는 탐식자야. 꼭 힘으로 이겨야 한다는 법은 없네.","JPN":"相手は貪食者だ。必ずしも力で勝たねばならないというわけではない。","ENG":"We are up against the Devourer. We don't have to beat her by force.","TWN":"對手是貪食者。不是非要靠力量取勝。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 저더러 어떡하라고요? 기가 막힌 작전이라도 짜낼까요?","JPN":"それじゃあ、私にどうしろというのですか？　すごい作戦でもひねり出しましょうか？","ENG":"Then what do you want me to do? Should I try to devise another genius plan?","TWN":"那你讓我怎麼辦？要制定一個不可思議的作戰計畫嗎？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"평생 공부만 알던 계집애가 세운 작전이 잘도 먹히겠네요.","JPN":"勉強しか知らなかった小娘が立てた作戦です。さぞやうまく行くでしょうね。","ENG":"As if a plan devised by a girl who spends her days reading books will be effective...","TWN":"我猜一個這輩子只知道學習的丫頭制定出來的作戰計畫，肯定會非常奏效呢。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니면 차라리 저주 인형을 쓰라고 하지 그러세요?","JPN":"あるいは、いっそ呪いの人形でも使えばいいかもしれませんね。","ENG":"Why not just ask me to use a voodoo doll, hmm?","TWN":"或者你乾脆說讓我使用詛咒娃娃好了？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저한테도 호수 같은 괴물이 섞였으면 효과가 있을지도 모르죠.","JPN":"私にも湖のような化け物が混ざっているのなら、効果があるかもですし。","ENG":"Perhaps it would have worked if I was part monster like the Lake.","TWN":"如果我也融合了湖水那種怪物，說不定會有效果。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양.","JPN":"マクレディー君。","ENG":"Regina.","TWN":"麥克蕾蒂。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전부 해 봤다고요… 내가 할 수 있는 건 전부!","JPN":"全部やってみましたわ……私にできることは全部！","ENG":"I have exhausted all options... I did everything I could!","TWN":"我全都試過了……我能做的一切！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 아무것도 얻지 못했어…! 전부 잃어 버리기만 했잖아…!","JPN":"それなのに、何も得ることができなかった……！　むしろ全部失うだけだった……！","ENG":"But I gained nothing...! And lost everything...!","TWN":"但是卻什麼都沒得到……！還失去了全都，不是嘛……！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};